function detectDomain(text) {
  const t = (text || "").toLowerCase();
  let best = { domain: "Custom", score: 0, icon: "🤖", personality: "Professional yet approachable" };
  for (const d of DOMAIN_MAP) {
    const score = d.keys.reduce((n, k) => n + (t.includes(k) ? 1 : 0), 0);
    if (score > best.score) best = { ...d, score };
  }
  return best;
}

function titleCaseFromPrompt(text, domain) {
  // Try to pull a noun-ish name; otherwise fall back to a domain label
  const labels = {
    HR: "HR Onboarding Assistant", IT: "IT Helpdesk Agent", Finance: "Payroll & Payslip Assistant",
    Sales: "Sales Enablement Agent", Procurement: "Procurement Assistant", "L&D": "Learning & Development Coach",
    Support: "Customer Support Agent", Custom: "Custom Workflow Agent",
  };
  return labels[domain] || "Custom Agent";
}

