function Btn({ children, onClick, variant = "primary", disabled, small, style: sx }) {
  const base = {
    padding: small ? "6px 14px" : "10px 22px",
    borderRadius: 10,
    fontSize: small ? 13 : 14,
    fontWeight: 700,
    fontFamily: "inherit",
    border: "none",
    cursor: disabled ? "default" : "pointer",
    transition: "all 0.2s",
    display: "inline-flex",
    alignItems: "center",
    gap: 6,
    ...sx,
  };
  const styles = {
    primary: { ...base, background: disabled ? C.border : `linear-gradient(135deg, ${C.pri}, #8b5cf6)`, color: disabled ? C.textDim : C.white },
    secondary: { ...base, background: C.surface, color: C.text, border: `1px solid ${C.border}` },
    ghost: { ...base, background: "transparent", color: C.textMuted, padding: small ? "4px 10px" : "8px 14px" },
    danger: { ...base, background: "#7f1d1d33", color: C.rose, border: `1px solid #7f1d1d66` },
    success: { ...base, background: `${C.emerald}18`, color: C.emerald, border: `1px solid ${C.emerald}44` },
  };
  return <button onClick={disabled ? undefined : onClick} style={styles[variant]}>{children}</button>;
}

function Badge({ children, color = C.pri }) {
  return (
    <span style={{
      padding: "3px 10px", borderRadius: 6, fontSize: 11, fontWeight: 700,
      background: color + "18", color, border: `1px solid ${color}33`,
      display: "inline-block",
    }}>{children}</span>
  );
}

function Card({ children, style: sx, onClick }) {
  return (
    <div onClick={onClick} style={{
      background: C.card, borderRadius: 14, border: `1px solid ${C.border}`,
      overflow: "hidden", cursor: onClick ? "pointer" : "default",
      backdropFilter: "blur(14px)", WebkitBackdropFilter: "blur(14px)",
      transition: "border-color 0.2s", ...sx,
    }}>{children}</div>
  );
}

function TabBar({ tabs, active, onChange }) {
  return (
    <div style={{
      display: "flex", gap: 0, borderBottom: `1px solid ${C.border}`,
      overflowX: "auto", padding: "0 8px", WebkitOverflowScrolling: "touch",
    }}>
      {tabs.map(t => (
        <button key={t.id} onClick={() => onChange(t.id)} style={{
          padding: "11px 14px", fontSize: 13, fontWeight: active === t.id ? 700 : 500,
          color: active === t.id ? C.priLight : C.textMuted,
          background: "none", border: "none", fontFamily: "inherit",
          borderBottom: active === t.id ? `2px solid ${C.pri}` : "2px solid transparent",
          cursor: "pointer", whiteSpace: "nowrap", transition: "all 0.15s",
        }}>
          <span style={{ marginRight: 5 }}>{t.icon}</span>{t.label}
        </button>
      ))}
    </div>
  );
}

function EmptyState({ icon, title, sub }) {
  return (
    <div style={{ textAlign: "center", padding: "48px 20px", color: C.textDim }}>
      <div style={{ fontSize: 40, marginBottom: 12 }}>{icon}</div>
      <div style={{ fontSize: 16, fontWeight: 700, color: C.textMuted, marginBottom: 6 }}>{title}</div>
      <div style={{ fontSize: 13 }}>{sub}</div>
    </div>
  );
}

