/* ─────────────────────────────────────────────
   EMBEDDABLE CHAT  (Layer 1 — drop into any dashboard)
   Loads when the URL contains  #embed=<base64 config>
   ───────────────────────────────────────────── */
function decodeEmbed() {
  try {
    const h = (typeof window !== "undefined" && window.location.hash) || "";
    const m = h.match(/embed=([^&]+)/);
    if (!m) return null;
    return JSON.parse(decodeURIComponent(atob(m[1])));
  } catch { return null; }
}

function EmbedChat({ cfg }) {
  const [msgs, setMsgs] = useState([]);
  const [input, setInput] = useState("");
  const [busy, setBusy] = useState(false);
  const endRef = useRef(null);
  useEffect(() => { endRef.current?.scrollIntoView({ behavior: "smooth" }); }, [msgs, busy]);

  const send = async (text) => {
    const q = (text ?? input).trim();
    if (!q || busy) return;
    setInput("");
    const next = [...msgs, { role: "user", content: q }];
    setMsgs(next); setBusy(true);
    try {
      const reply = await callClaude(cfg.systemPrompt || "You are a helpful assistant.", next);
      setMsgs(m => [...m, { role: "assistant", content: reply }]);
    } catch {
      setMsgs(m => [...m, { role: "assistant", content: "Sorry — I couldn't reach the model just now. Please try again." }]);
    } finally { setBusy(false); }
  };

  return (
    <div style={{ height: "100vh", display: "flex", flexDirection: "column", background: C.bg, color: C.text, fontFamily: "'Inter', -apple-system, system-ui, sans-serif" }}>
      <style>{`@import url('https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700;800&display=swap'); *{box-sizing:border-box;margin:0;padding:0} input::placeholder{color:${C.textDim}} ::-webkit-scrollbar{width:5px} ::-webkit-scrollbar-thumb{background:${C.border};border-radius:3px}`}</style>
      <div style={{ display: "flex", alignItems: "center", gap: 10, padding: "12px 16px", borderBottom: `1px solid ${C.border}`, background: C.card }}>
        <img src={FA_LOGO} alt="FieldAssist" style={{ height: 18, width: "auto" }} />
        <div style={{ width: 1, height: 18, background: C.border }} />
        <div style={{ fontSize: 14, fontWeight: 700, color: C.white }}>{cfg.name || "Assistant"}</div>
        <span style={{ marginLeft: "auto", width: 8, height: 8, borderRadius: "50%", background: C.emerald }} />
      </div>
      <div style={{ flex: 1, overflowY: "auto", padding: 16, display: "flex", flexDirection: "column", gap: 12 }}>
        {msgs.length === 0 && (
          <div style={{ margin: "auto", textAlign: "center", maxWidth: 280 }}>
            <div style={{ fontSize: 32, marginBottom: 8 }}>🤖</div>
            <div style={{ fontSize: 14, color: C.textMuted, lineHeight: 1.5 }}>Hi! I'm {cfg.name || "your assistant"}. Ask me anything to get started.</div>
          </div>
        )}
        {msgs.map((m, i) => (
          <div key={i} style={{ alignSelf: m.role === "user" ? "flex-end" : "flex-start", maxWidth: "82%" }}>
            <div style={{
              padding: "10px 14px", borderRadius: 14, fontSize: 14, lineHeight: 1.55, whiteSpace: "pre-wrap",
              background: m.role === "user" ? `linear-gradient(135deg, ${C.pri}, ${C.sec})` : C.surface,
              color: m.role === "user" ? "#fff" : C.text,
              border: m.role === "user" ? "none" : `1px solid ${C.border}`,
            }}>{m.content}</div>
          </div>
        ))}
        {busy && <div style={{ alignSelf: "flex-start", padding: "10px 14px", borderRadius: 14, background: C.surface, border: `1px solid ${C.border}`, color: C.textDim, fontSize: 14 }}>typing…</div>}
        <div ref={endRef} />
      </div>
      <div style={{ display: "flex", gap: 8, padding: 12, borderTop: `1px solid ${C.border}`, background: C.card }}>
        <input value={input} onChange={e => setInput(e.target.value)} onKeyDown={e => { if (e.key === "Enter") send(); }}
          placeholder="Type your message…"
          style={{ flex: 1, padding: "11px 14px", fontSize: 14, background: C.bg, color: C.text, border: `1px solid ${C.border}`, borderRadius: 10, outline: "none", fontFamily: "inherit" }} />
        <button onClick={() => send()} disabled={busy || !input.trim()} style={{
          padding: "0 18px", borderRadius: 10, border: "none", cursor: "pointer", fontFamily: "inherit",
          fontSize: 14, fontWeight: 700, color: "#fff", background: `linear-gradient(135deg, ${C.pri}, ${C.sec})`,
          opacity: busy || !input.trim() ? 0.5 : 1,
        }}>Send</button>
      </div>
      <div style={{ textAlign: "center", fontSize: 10, color: C.textDim, padding: "6px 0", background: C.card }}>Powered by FieldAssist · Agent Studio</div>
    </div>
  );
}

function ExportModal({ bp, onClose }) {
  const [copied, setCopied] = useState(null);
  const embedCfg = { name: bp.agentName, domain: bp.domain, systemPrompt: bp.systemPrompt };
  const embedBase = (typeof window !== "undefined") ? (window.location.origin + window.location.pathname) : "https://YOUR-APP.vercel.app/";
  const embedSnippet = `<iframe\n  src="${embedBase}#embed=${btoa(encodeURIComponent(JSON.stringify(embedCfg)))}"\n  width="400" height="620"\n  style="border:0;border-radius:16px;overflow:hidden"\n  title="${bp.agentName}">\n</iframe>`;
  const sections = [
    { key: "embed", label: "🔗 Embed in your dashboard (paste this iframe)", data: embedSnippet },
    { key: "full", label: "Full Blueprint (JSON)", data: JSON.stringify(bp, null, 2) },
    { key: "prompt", label: "System Prompt Only", data: bp.systemPrompt || "" },
    { key: "config", label: "Agent Config (for API)", data: JSON.stringify({
      name: bp.agentName, domain: bp.domain, system: bp.systemPrompt,
      guardrails: bp.guardrails, tools: (bp.tools || []).map(t => t.name),
      channels: bp.deploymentChannels, memory: bp.memoryConfig,
    }, null, 2) },
  ];

  const copy = (key, data) => {
    navigator.clipboard.writeText(data).then(() => {
      setCopied(key);
      setTimeout(() => setCopied(null), 2000);
    }).catch(() => {});
  };

  return (
    <div style={{
      position: "fixed", inset: 0, background: "rgba(0,0,0,0.7)", zIndex: 1000,
      display: "flex", alignItems: "center", justifyContent: "center", padding: 20,
    }} onClick={onClose}>
      <div onClick={e => e.stopPropagation()} style={{
        background: C.card, borderRadius: 16, border: `1px solid ${C.border}`,
        width: "100%", maxWidth: 560, maxHeight: "85vh", overflowY: "auto",
      }}>
        <div style={{
          display: "flex", justifyContent: "space-between", alignItems: "center",
          padding: "16px 22px", borderBottom: `1px solid ${C.border}`,
        }}>
          <span style={{ fontSize: 18, fontWeight: 800, color: C.white }}>📥 Export {bp.agentName}</span>
          <Btn small variant="ghost" onClick={onClose}>✕</Btn>
        </div>
        <div style={{ padding: 22, display: "grid", gap: 16 }}>
          {sections.map(s => (
            <div key={s.key}>
              <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 8 }}>
                <span style={{ fontSize: 13, fontWeight: 700, color: C.textMuted }}>{s.label}</span>
                <Btn small variant={copied === s.key ? "success" : "secondary"} onClick={() => copy(s.key, s.data)}>
                  {copied === s.key ? "✓ Copied" : "Copy"}
                </Btn>
              </div>
              <div style={{
                background: C.bg, borderRadius: 10, padding: 14, border: `1px solid ${C.border}`,
                fontFamily: "'JetBrains Mono', monospace", fontSize: 11, lineHeight: 1.6,
                color: C.textMuted, maxHeight: 160, overflowY: "auto", whiteSpace: "pre-wrap",
                wordBreak: "break-all",
              }}>{s.data}</div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}

/* ─────────────────────────────────────────────
   MAIN APP
   ───────────────────────────────────────────── */
function LoginScreen({ onSignIn }) {
  const [err, setErr] = useState(null);
  const [busy, setBusy] = useState(false);
  const go = async () => { setErr(null); setBusy(true); try { await onSignIn(); } catch (e) { setErr(e?.message || "Sign-in failed"); setBusy(false); } };
  return (
    <div style={{ minHeight: "100vh", background: C.bg, color: C.text, display: "flex", alignItems: "center", justifyContent: "center", padding: 20, fontFamily: "'Inter', -apple-system, system-ui, sans-serif" }}>
      <style>{`@import url('https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700;800&display=swap'); *{box-sizing:border-box;margin:0;padding:0}`}</style>
      <div aria-hidden="true" style={{ position: "fixed", inset: 0, pointerEvents: "none", background: "radial-gradient(620px 400px at 80% 6%, rgba(58,123,255,0.18), transparent 60%), radial-gradient(560px 380px at 10% 94%, rgba(255,121,172,0.15), transparent 60%)" }} />
      <div style={{ position: "relative", zIndex: 1, width: "100%", maxWidth: 400, background: C.card, backdropFilter: "blur(14px)", WebkitBackdropFilter: "blur(14px)", border: `1px solid ${C.border}`, borderRadius: 18, padding: "36px 30px", textAlign: "center" }}>
        <img src={FA_LOGO} alt="FieldAssist" style={{ height: 26, width: "auto", marginBottom: 18 }} />
        <div style={{ fontSize: 22, fontWeight: 800, color: C.white, marginBottom: 6 }}>Agent Studio</div>
        <div style={{ fontSize: 13.5, color: C.textMuted, lineHeight: 1.5, marginBottom: 26 }}>Sign in with your FieldAssist Google account to build and manage your agents.</div>
        <button onClick={go} disabled={busy} style={{ display: "flex", alignItems: "center", justifyContent: "center", gap: 10, width: "100%", padding: "12px", borderRadius: 10, border: "none", cursor: "pointer", fontFamily: "inherit", fontSize: 14, fontWeight: 700, color: "#fff", background: `linear-gradient(135deg, ${C.pri}, ${C.sec})`, opacity: busy ? 0.6 : 1 }}>
          <svg width="18" height="18" viewBox="0 0 48 48"><path fill="#fff" d="M44.5 20H24v8.5h11.8C34.7 33.4 30 37 24 37c-7.2 0-13-5.8-13-13s5.8-13 13-13c3.3 0 6.3 1.2 8.6 3.3l6-6C42.6 4.9 33.8 1 24 1 11.8 1 2 10.8 2 23s9.8 22 22 22c11 0 21-8 21-22 0-1.3-.2-2.7-.5-3z"/></svg>
          {busy ? "Signing in…" : "Sign in with Google"}
        </button>
        {err && <div style={{ marginTop: 14, fontSize: 12, color: C.rose }}>{err}</div>}
        <div style={{ marginTop: 22, fontSize: 11, color: C.textDim }}>Powered by FieldAssist</div>
      </div>
    </div>
  );
}

function AdminScreen({ requests, users = [], adminEmail, orgAgents, onApprove, onReject, onUnpublish, onOpen, onBack }) {
  const timeAgo = (ts) => {
    if (!ts) return "—";
    const m = Math.floor((Date.now() - ts) / 60000);
    if (m < 1) return "just now";
    if (m < 60) return `${m}m ago`;
    const h = Math.floor(m / 60);
    if (h < 24) return `${h}h ago`;
    return `${Math.floor(h / 24)}d ago`;
  };
  const Row = (a, actions) => (
    <Card key={a._id} style={{ display: "flex", alignItems: "center", gap: 12, padding: "14px 18px" }}>
      <div style={{ width: 36, height: 36, borderRadius: 9, display: "flex", alignItems: "center", justifyContent: "center", fontSize: 18, flexShrink: 0, background: `linear-gradient(135deg, ${C.pri}33, ${C.sec}33)` }}>🤖</div>
      <div style={{ flex: 1, minWidth: 0, cursor: "pointer" }} onClick={() => onOpen(a)}>
        <div style={{ fontSize: 14, fontWeight: 700, color: C.white, overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>{a.agentName}</div>
        <div style={{ fontSize: 12, color: C.textDim, overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>by {a._ownerName || a._ownerEmail || "unknown"} · {a.domain}</div>
      </div>
      <div style={{ display: "flex", gap: 8 }}>{actions}</div>
    </Card>
  );
  return (
    <div style={{ maxWidth: 760, margin: "0 auto", padding: "20px 16px 40px" }}>
      <div style={{ display: "flex", alignItems: "center", gap: 12, marginBottom: 18 }}>
        <Btn small variant="ghost" onClick={onBack}>← Back</Btn>
        <div style={{ fontSize: 20, fontWeight: 800, color: C.white }}>🛡 Admin</div>
      </div>

      <div style={{ fontSize: 12, fontWeight: 700, color: C.textDim, textTransform: "uppercase", letterSpacing: 1, margin: "4px 0 10px" }}>
        People · {users.length}
      </div>
      <div style={{ display: "grid", gap: 8, marginBottom: 8 }}>
        {users.length === 0 && <Card style={{ padding: "16px 18px", color: C.textDim, fontSize: 13 }}>No one has signed in yet. People appear here after their first login.</Card>}
        {users.map(u => (
          <Card key={u.uid} style={{ display: "flex", alignItems: "center", gap: 12, padding: "12px 16px" }}>
            {u.photo
              ? <img src={u.photo} alt="" style={{ width: 32, height: 32, borderRadius: "50%", flexShrink: 0 }} />
              : <div style={{ width: 32, height: 32, borderRadius: "50%", flexShrink: 0, background: C.surface }} />}
            <div style={{ flex: 1, minWidth: 0 }}>
              <div style={{ fontSize: 13.5, fontWeight: 700, color: C.white, overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>
                {u.name || "—"} {u.email === adminEmail && <Badge color={C.pri}>Admin</Badge>}
              </div>
              <div style={{ fontSize: 12, color: C.textDim, overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>{u.email}</div>
            </div>
            <div style={{ fontSize: 11, color: C.textDim, flexShrink: 0 }}>active {timeAgo(u.lastSeen)}</div>
          </Card>
        ))}
      </div>

      <div style={{ fontSize: 12, fontWeight: 700, color: C.textDim, textTransform: "uppercase", letterSpacing: 1, margin: "26px 0 10px" }}>
        Pending requests · {requests.length}
      </div>
      <div style={{ display: "grid", gap: 10 }}>
        {requests.length === 0 && <Card style={{ padding: "16px 18px", color: C.textDim, fontSize: 13 }}>No pending requests right now.</Card>}
        {requests.map(a => Row(a, <>
          <Btn small variant="success" onClick={() => onApprove(a._id)}>✓ Approve</Btn>
          <Btn small variant="danger" onClick={() => onReject(a._id)}>Decline</Btn>
        </>))}
      </div>

      <div style={{ fontSize: 12, fontWeight: 700, color: C.textDim, textTransform: "uppercase", letterSpacing: 1, margin: "26px 0 10px" }}>
        Published org-wide · {orgAgents.length}
      </div>
      <div style={{ display: "grid", gap: 10 }}>
        {orgAgents.length === 0 && <Card style={{ padding: "16px 18px", color: C.textDim, fontSize: 13 }}>Nothing published yet.</Card>}
        {orgAgents.map(a => Row(a, <Btn small variant="secondary" onClick={() => onUnpublish(a._id)}>Unpublish</Btn>))}
      </div>
    </div>
  );
}

function StudioApp() {
  const [screen, setScreen] = useState("builder");
  const [agents, setAgents] = useState([]);
  const [activeIdx, setActiveIdx] = useState(-1);
  const [phaseIdx, setPhaseIdx] = useState(0);
  const [error, setError] = useState(null);
  const [showExport, setShowExport] = useState(false);
  const [loaded, setLoaded] = useState(false);
  const [user, setUser] = useState(null);
  const [authReady, setAuthReady] = useState(false);

  useEffect(() => onAuth(u => { setUser(u); setAuthReady(true); }), []);

  const [requests, setRequests] = useState([]);
  const [users, setUsers] = useState([]);
  const admin = user ? isAdminEmail(user.email) : false;
  const bpOnly = (a) => { const { _id, _ownerUid, _ownerName, _ownerEmail, _visibility, _orgStatus, ...bp } = a; return bp; };

  const refresh = useCallback(async (selectId) => {
    if (!user) return;
    const all = await loadAllAgents(user);
    setAgents(all); setLoaded(true);
    if (selectId !== undefined) {
      const i = all.findIndex(a => a._id === selectId);
      setActiveIdx(i >= 0 ? i : -1);
    }
    if (isAdminEmail(user.email)) { setRequests(await loadPendingRequests()); setUsers(await loadAllUsers()); }
  }, [user]);

  // Load this user's own + org-shared agents when they sign in.
  useEffect(() => {
    if (!user) { setAgents([]); setLoaded(false); setRequests([]); return; }
    setLoaded(false);
    upsertUserProfile(user);
    loadAllAgents(user).then(a => { setAgents(a); setLoaded(true); });
    if (isAdminEmail(user.email)) { loadPendingRequests().then(setRequests); loadAllUsers().then(setUsers); }
  }, [user]);

  const activeBp = activeIdx >= 0 && activeIdx < agents.length ? agents[activeIdx] : null;

  const forgeAgent = useCallback(async (promptText) => {
    if (!promptText || !promptText.trim()) return;
    setScreen("forging");
    setPhaseIdx(0);
    setError(null);

    // Animate phases
    let idx = 0;
    const interval = setInterval(() => {
      idx++;
      if (idx < FORGE_PHASES.length) setPhaseIdx(idx);
      else clearInterval(interval);
    }, 1600);

    let bp;
    let usedDemo = false;
    try {
      const raw = await callClaude(SYSTEM_PROMPT, [{ role: "user", content: promptText }]);
      bp = parseJSON(raw);
    } catch (err) {
      // No API / network / parse failure → fall back to the offline generator
      // so the forge always produces a complete blueprint (zero-setup demo mode).
      console.warn("Falling back to offline blueprint:", err?.message);
      bp = buildDemoBlueprint(promptText);
      usedDemo = true;
    }

    try {
      clearInterval(interval);
      setPhaseIdx(FORGE_PHASES.length);

      // Ensure required fields
      bp.agentName = bp.agentName || "Unnamed Agent";
      bp.tagline = bp.tagline || "AI-powered assistant";
      bp.domain = bp.domain || "Custom";
      bp.systemPrompt = bp.systemPrompt || "You are a helpful assistant.";
      bp.guardrails = bp.guardrails || [];
      bp.tools = bp.tools || [];
      bp.workflow = bp.workflow || [];
      bp.knowledgeSources = bp.knowledgeSources || [];
      bp.sampleConversation = bp.sampleConversation || [];
      bp.features = bp.features || [];
      bp.memoryConfig = bp.memoryConfig || {};
      bp.deploymentChannels = bp.deploymentChannels || ["Web"];
      bp.complexityScore = bp.complexityScore || 5;
      bp.kpis = bp.kpis || [];
      bp.limitations = bp.limitations || [];
      bp._createdAt = Date.now();
      bp._sourcePrompt = promptText;
      bp._demoMode = usedDemo;

      const id = await createAgent(user, bp);
      await refresh(id);
      setTimeout(() => setScreen("blueprint"), 600);
    } catch (err) {
      // Last-resort safety net — should essentially never hit now.
      clearInterval(interval);
      console.error("Forge error:", err);
      setError("Something went wrong building the agent. Please try again.");
      setScreen("builder");
    }
  }, [user, refresh]);

  const handleClone = async () => {
    if (!activeBp || !user) return;
    const clone = { ...JSON.parse(JSON.stringify(bpOnly(activeBp))), agentName: activeBp.agentName + " (Copy)", _createdAt: Date.now(), _demoMode: false, _sourcePrompt: undefined };
    const id = await createAgent(user, clone);
    await refresh(id);
    setScreen("blueprint");
  };

  const handleDelete = async () => {
    if (!activeBp || !user) return;
    try { if (activeBp._id) await deleteAgentDoc(activeBp._id); } catch (e) { console.error(e); }
    setActiveIdx(-1);
    setScreen("builder");
    await refresh();
  };

  const openAgent = (i) => { setActiveIdx(i); setScreen("blueprint"); };

  const updateAgent = useCallback(async (patch) => {
    if (!activeBp) return;
    const merged = { ...activeBp, ...patch };
    setAgents(prev => prev.map(a => a._id === activeBp._id ? merged : a));
    try { if (activeBp._id) await updateAgentBlueprint(activeBp._id, merged); } catch (e) { console.error(e); }
  }, [activeBp]);

  const onRequestOrg = async () => {
    if (!activeBp?._id) return;
    try { await requestOrg(activeBp._id); } catch (e) { console.error(e); }
    await refresh(activeBp._id);
  };

  const adminApprove = async (id) => { try { await approveOrg(id); } catch (e) { console.error(e); } await refresh(); };
  const adminReject = async (id) => { try { await rejectOrg(id); } catch (e) { console.error(e); } await refresh(); };
  const adminUnpublish = async (id) => { try { await unpublishOrg(id); } catch (e) { console.error(e); } await refresh(); };

  if (!authReady) {
    return <div style={{ minHeight: "100vh", background: C.bg, color: C.textMuted, display: "flex", alignItems: "center", justifyContent: "center", fontFamily: "'Inter', sans-serif" }}>Loading…</div>;
  }
  if (!user) {
    return <LoginScreen onSignIn={signInWithGoogle} />;
  }

  return (
    <div style={{
      minHeight: "100vh", background: C.bg, color: C.text,
      fontFamily: "'Inter', -apple-system, system-ui, sans-serif",
      display: "flex", alignItems: "stretch",
    }}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700;800;900&family=JetBrains+Mono:wght@400;500;600&display=swap');
        * { box-sizing: border-box; margin: 0; padding: 0; }
        @keyframes forgePulse { 0%,100% { transform: scale(1) rotate(0deg); } 25% { transform: scale(1.12) rotate(-8deg); } 75% { transform: scale(1.12) rotate(8deg); } }
        @keyframes spin { to { transform: rotate(360deg); } }
        @keyframes dotPulse { 0%,80%,100% { opacity: 0.3; } 40% { opacity: 1; } }
        @keyframes fadeUp { from { opacity: 0; transform: translateY(12px); } to { opacity: 1; transform: translateY(0); } }
        input::placeholder, textarea::placeholder { color: ${C.textDim}; }
        ::-webkit-scrollbar { width: 5px; height: 5px; }
        ::-webkit-scrollbar-track { background: transparent; }
        ::-webkit-scrollbar-thumb { background: ${C.border}; border-radius: 3px; }
        button:hover { filter: brightness(1.1); }
        .brandMobile { display: none; }
        .railItem:hover { background: ${C.surface}; }
        @media (max-width: 760px) {
          .rail { display: none !important; }
          .brandMobile { display: flex !important; }
        }
      `}</style>

      {/* ── AURORA BACKDROP ── */}
      <div aria-hidden="true" style={{
        position: "fixed", inset: 0, pointerEvents: "none", zIndex: 0,
        background: "radial-gradient(620px 400px at 80% 6%, rgba(58,123,255,0.18), transparent 60%), radial-gradient(560px 380px at 10% 94%, rgba(255,121,172,0.15), transparent 60%)",
      }} />

      {/* ── CONSOLE RAIL ── */}
      <aside className="rail" style={{
        width: 212, flexShrink: 0, position: "sticky", top: 0, height: "100vh",
        overflowY: "auto", zIndex: 50, display: "flex", flexDirection: "column",
        padding: "16px 12px", background: "rgba(9,13,28,0.78)",
        backdropFilter: "blur(16px)", WebkitBackdropFilter: "blur(16px)",
        borderRight: `1px solid ${C.border}`,
      }}>
        <div onClick={() => { setScreen("builder"); setActiveIdx(-1); }}
          style={{ display: "flex", alignItems: "center", gap: 8, cursor: "pointer", padding: "2px 6px 12px" }}>
          <img src={FA_LOGO} alt="FieldAssist" style={{ height: 20, width: "auto", display: "block" }} />
        </div>
        <div style={{ fontSize: 9.5, color: C.textDim, fontWeight: 700, letterSpacing: 1, padding: "0 6px 10px" }}>AGENT STUDIO</div>
        <button onClick={() => { setScreen("builder"); setActiveIdx(-1); }} style={{
          display: "flex", alignItems: "center", gap: 8, width: "100%", padding: "9px 12px",
          borderRadius: 10, border: "none", cursor: "pointer", fontFamily: "inherit",
          fontSize: 13, fontWeight: 700, color: C.white, marginBottom: 16,
          background: `linear-gradient(135deg, ${C.pri}, ${C.sec})`,
        }}>＋ New agent</button>
        {admin && (
          <button onClick={() => setScreen("admin")} style={{
            display: "flex", alignItems: "center", gap: 8, width: "100%", padding: "8px 12px",
            borderRadius: 9, border: `1px solid ${C.border}`, cursor: "pointer", fontFamily: "inherit",
            fontSize: 12.5, fontWeight: 700, color: requests.length ? C.amber : C.textMuted,
            background: "transparent", marginBottom: 14,
          }}>🛡 Requests {requests.length ? `· ${requests.length}` : ""}</button>
        )}

        {(() => {
          const mine = agents.filter(a => a._ownerUid === user.uid);
          const org = agents.filter(a => a._visibility === "org" && a._ownerUid !== user.uid);
          const Item = (a) => {
            const on = activeBp && activeBp._id === a._id && screen !== "builder";
            return (
              <button key={a._id} className="railItem" onClick={() => openAgent(agents.findIndex(x => x._id === a._id))} style={{
                display: "flex", alignItems: "center", gap: 8, width: "100%", textAlign: "left",
                padding: "8px 10px", borderRadius: 8, border: "none", cursor: "pointer",
                fontFamily: "inherit", background: on ? C.surface : "transparent",
              }}>
                <span style={{ width: 7, height: 7, borderRadius: "50%", flexShrink: 0, background: a._visibility === "org" ? C.emerald : on ? C.sec : C.pri }} />
                <span style={{ flex: 1, minWidth: 0, fontSize: 12.5, fontWeight: on ? 700 : 500, color: on ? C.white : C.textMuted, overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>{a.agentName}</span>
              </button>
            );
          };
          return (
            <div style={{ display: "flex", flexDirection: "column", gap: 2, overflowY: "auto" }}>
              <div style={{ fontSize: 10, color: C.textDim, fontWeight: 700, letterSpacing: 1, padding: "0 6px 6px", textTransform: "uppercase" }}>My agents · {mine.length}</div>
              {mine.length === 0 && <div style={{ fontSize: 12, color: C.textDim, padding: "2px 8px 8px", lineHeight: 1.5 }}>None yet — build one →</div>}
              {mine.map(Item)}
              <div style={{ fontSize: 10, color: C.textDim, fontWeight: 700, letterSpacing: 1, padding: "14px 6px 6px", textTransform: "uppercase" }}>Org agents · {org.length}</div>
              {org.length === 0 && <div style={{ fontSize: 12, color: C.textDim, padding: "2px 8px", lineHeight: 1.5 }}>No shared agents yet.</div>}
              {org.map(Item)}
            </div>
          );
        })()}
        <div style={{ marginTop: "auto", paddingTop: 12, borderTop: `1px solid ${C.border}` }}>
          <div style={{ display: "flex", alignItems: "center", gap: 8, padding: "8px 2px" }}>
            {user.photoURL
              ? <img src={user.photoURL} alt="" style={{ width: 26, height: 26, borderRadius: "50%" }} />
              : <div style={{ width: 26, height: 26, borderRadius: "50%", background: C.surface }} />}
            <div style={{ flex: 1, minWidth: 0 }}>
              <div style={{ fontSize: 11.5, color: C.text, fontWeight: 600, overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>{user.displayName || "User"}</div>
              <div style={{ fontSize: 10, color: C.textDim, overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>{user.email}</div>
            </div>
          </div>
          <button onClick={signOutUser} style={{ width: "100%", padding: "7px", borderRadius: 8, border: `1px solid ${C.border}`, background: "transparent", color: C.textMuted, cursor: "pointer", fontFamily: "inherit", fontSize: 11.5, marginBottom: 10 }}>Sign out</button>
          <div style={{ fontSize: 10.5, fontFamily: "'JetBrains Mono', monospace", color: C.textDim }}>
            v1.0 · {agents.length} agent{agents.length !== 1 ? "s" : ""} live
          </div>
        </div>
      </aside>

      {/* ── MAIN ── */}
      <div className="main" style={{ flex: 1, minWidth: 0, position: "relative", zIndex: 1 }}>
      {/* ── HEADER ── */}
      <div style={{
        padding: "12px 20px", borderBottom: `1px solid ${C.border}`,
        display: "flex", alignItems: "center", justifyContent: "space-between",
        background: C.card, position: "sticky", top: 0, zIndex: 100,
      }}>
        <div
          className="brandMobile"
          onClick={() => { setScreen("builder"); setActiveIdx(-1); }}
          style={{ alignItems: "center", gap: 10, cursor: "pointer" }}
        >
          <img src={FA_LOGO} alt="FieldAssist" style={{ height: 24, width: "auto", display: "block" }} />
          <div style={{ width: 1, height: 22, background: C.border }} />
          <div>
            <div style={{ fontSize: 15, fontWeight: 800, color: C.white, lineHeight: 1, letterSpacing: -0.3 }}>Agent Studio</div>
            <div style={{ fontSize: 9.5, color: C.textDim, fontWeight: 600, letterSpacing: 0.6, marginTop: 2 }}>
              BUILD AGENTS WITH WORDS
            </div>
          </div>
        </div>
        <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
          {agents.length > 0 && (
            <Badge color={C.sec}>{agents.length} agent{agents.length !== 1 ? "s" : ""}</Badge>
          )}
          {screen !== "builder" && (
            <Btn small variant="secondary" onClick={() => { setScreen("builder"); setActiveIdx(-1); }}>
              + New Agent
            </Btn>
          )}
        </div>
      </div>

      {/* ── ERROR BANNER ── */}
      {error && (
        <div style={{
          margin: "12px 16px 0", padding: "12px 18px", borderRadius: 10,
          background: "#7f1d1d22", border: "1px solid #7f1d1d66", color: C.rose,
          fontSize: 13, display: "flex", justifyContent: "space-between", alignItems: "center",
        }}>
          <span>{error}</span>
          <Btn small variant="ghost" onClick={() => setError(null)}>✕</Btn>
        </div>
      )}

      {/* ── SCREENS ── */}
      <div style={{ animation: "fadeUp 0.35s ease" }} key={screen + activeIdx}>
        {screen === "builder" && (
          <BuilderScreen
            onForge={forgeAgent}
            agents={agents}
            onOpen={openAgent}
          />
        )}

        {screen === "forging" && <ForgeScreen phaseIdx={phaseIdx} />}

        {screen === "blueprint" && activeBp && (
          <BlueprintScreen
            bp={activeBp}
            onTest={() => setScreen("testing")}
            onBack={() => { setScreen("builder"); setActiveIdx(-1); }}
            onExport={() => setShowExport(true)}
            onClone={handleClone}
            onDelete={handleDelete}
            onUpdate={updateAgent}
            currentUid={user.uid}
            admin={admin}
            onRequestOrg={onRequestOrg}
          />
        )}

        {screen === "testing" && activeBp && (
          <TestScreen bp={activeBp} onBack={() => setScreen("blueprint")} />
        )}

        {screen === "admin" && admin && (
          <AdminScreen
            requests={requests}
            users={users}
            adminEmail={user.email}
            orgAgents={agents.filter(a => a._visibility === "org")}
            onApprove={adminApprove}
            onReject={adminReject}
            onUnpublish={adminUnpublish}
            onOpen={(a) => openAgent(agents.findIndex(x => x._id === a._id))}
            onBack={() => setScreen("builder")}
          />
        )}
      </div>
      </div>

      {/* ── EXPORT MODAL ── */}
      {showExport && activeBp && (
        <ExportModal bp={activeBp} onClose={() => setShowExport(false)} />
      )}
    </div>
  );
}

export default function FAAgentStudio() {
  const cfg = decodeEmbed();
  return cfg ? <EmbedChat cfg={cfg} /> : <StudioApp />;
}
